import { Component } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MatButtonModule } from '@angular/material/button';
import { Router } from '@angular/router';


@Component({
  selector: 'app-review-continue',
  standalone: true,
  imports: [MatCardModule, MatCheckboxModule, MatButtonModule],
  templateUrl: './review-continue.component.html',
  styleUrl: './review-continue.component.css'
})
export class ReviewContinueComponent {
  receivedBankDetails: any = null;

  constructor(private routes: Router,) {

  }
  ngOnInit() {
    this.receivedBankDetails = JSON.parse(sessionStorage.getItem("addressAndBankDetails") || '{}');

  }

  checked: boolean = false;

  changeChecked = (): void => {
    if (this.checked) {
      this.checked = false;
    } else {
      this.checked = true;
    }

  }

  goToBankForm = (): void => {
    this.routes.navigate(['/pdfa/bankForm']);
  }

  save() {
    this.routes.navigate(['/port-agent-form']);
  }
}
